SET client_encoding TO 'UTF8';

SET check_function_bodies = false;





CREATE OR REPLACE FUNCTION fpb_tel_get_atm_status (as_conno char ) RETURNS varchar AS $body$
DECLARE

ls_status sc_atm_lon_card.modify_status%TYPE;
ls_close sc_atm_lon_card.close_status%type;

BEGIN
  SELECT sc_atm_lon_card.modify_status , close_status
  INTO STRICT ls_status,ls_close
  FROM sc_atm_lon_card
  WHERE sc_atm_lon_card.loan_contract_no = as_conno;
  if ls_close = '1' then
    return 'ปิดสัญญา';
  else
    --0 ปกติ,H เตรียมงด,U เตรียมปลดงด,1 เปลี่ยนวงเงิน
    case ls_status
      when 'D' then
        return 'งดกด ATM แล้ว';
      when 'U' then
        return 'ขอปลดการงด ATM';
     when 'C' then
        return 'ยกเลิก ATM แล้ว';
     when 'N' then
        return 'ขอใช้ ATM';
      when '0' then
        return 'ปกติ';
      when 'H' then
        return 'ของดกด ATM';
      when 'F' then
        return 'ขอยกเลิก ATM';
      when '1' then
        return 'กำลังขอเปลี่ยนแปลง';
      when 'W' then
        return 'รอ Mapping';
      else
        return ls_status;
     end case;
  end if;

END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
-- REVOKE ALL ON FUNCTION fpb_tel_get_atm_status (as_conno char ) FROM PUBLIC;

